import re
from typing import Dict, List, Any

class ScoringAlgorithm:
    def __init__(self, job_description_data: Dict[str, Any]):
        """
        Initializes the ScoringAlgorithm with job description data containing scoring criteria.

        job_description_data format:
        {
            "evaluation_criteria": {
                "Code quality": {
                    "keywords": {"comments": 1.0, "error handling": 1.0, "tests": 0.5},
                    "max_score": 5
                },
                "Problem-solving skills": {
                    "keywords": {"analysis": 1.0, "steps": 1.0, "edge cases": 0.5},
                    "max_score": 5
                },
                "Teamwork and collaboration": {
                    "keywords": {"communication": 1.0, "conflict resolution": 1.0, "peer review": 0.5},
                    "max_score": 5
                }
            }
        }
        """
        self.criteria_config = job_description_data.get("evaluation_criteria", {})

    def evaluate_responses(self, candidate_responses: Dict[str, str]) -> Dict[str, Any]:
        """
        Evaluates the candidate's responses against each configured criterion.

        Returns a dict:
        {
            "Code quality": {"raw_score": 3.5, "normalized_score": 4},
            ...
        }
        """
        results = {}
        for criterion, config in self.criteria_config.items():
            raw = self._compute_raw_score(criterion, config, candidate_responses)
            max_score = config.get("max_score", 5)
            norm = self._normalize_score(raw, config)
            results[criterion] = {
                "raw_score": round(raw, 2),
                "normalized_score": min(max(round(norm), 0), max_score)
            }
        return results

    def _compute_raw_score(self, criterion: str, config: Dict[str, Any],
                           responses: Dict[str, str]) -> float:
        """
        Computes the raw score by summing weights for keyword occurrences.
        """
        keywords: Dict[str, float] = config.get("keywords", {})
        raw_score = 0.0
        for question, answer in responses.items():
            text = answer.lower()
            for keyword, weight in keywords.items():
                # count occurrences
                count = len(re.findall(r'\b' + re.escape(keyword.lower()) + r'\b', text))
                raw_score += count * weight
        return raw_score

    def _normalize_score(self, raw_score: float, config: Dict[str, Any]) -> float:
        """
        Normalizes raw score to the defined max_score.
        E.g., if total possible weight is W, scaled to max_score.
        """
        keywords = config.get("keywords", {})
        max_score = config.get("max_score", 5)
        # maximum possible raw = sum(weight * times) 
        # but we don't know times; assume one mention per keyword => max_raw = sum(weights)
        max_raw = sum(keywords.values())
        if max_raw <= 0:
            return 0.0
        return (raw_score / max_raw) * max_score

if __name__ == "__main__":
    # Example usage:
    job_description_data = {
        "evaluation_criteria": {
            "Code quality": {
                "keywords": {"comments": 1.0, "error handling": 1.0, "tests": 0.5},
                "max_score": 5
            },
            "Problem-solving skills": {
                "keywords": {"analysis": 1.0, "steps": 1.0, "edge cases": 0.5},
                "max_score": 5
            },
            "Teamwork and collaboration": {
                "keywords": {"communication": 1.0, "conflict resolution": 1.0, "peer review": 0.5},
                "max_score": 5
            }
        }
    }

    candidate_responses = {
        "Describe a time you faced a coding challenge": (
            "I wrote comments extensively, added error handling, and "
            "wrote tests to validate edge cases."
        ),
        "How do you approach solving a problem?": (
            "I start with deep analysis of requirements, list steps, "
            "and consider edge cases before implementing."
        ),
        "Tell me about a time you worked in a team": (
            "We had strong communication, conducted peer review sessions, "
            "and used conflict resolution techniques when needed."
        )
    }

    scorer = ScoringAlgorithm(job_description_data)
    scores = scorer.evaluate_responses(candidate_responses)
    print("Candidate Scores:", scores)
```

